Yes, here is a complete Terraform configuration example:```terraform
provider "openstack" {}

resource "openstack_compute_instance_v2" "myvm" {
  name = "myvm"
  flavor_id = "0351ddb0-00d0-4269-80d3-913029d1a111"
  key_pair = "Aluminum"
  security_groups = ["default"]

  network {
    name = "my-tenant-net"
  }

  block_device {
    uuid = "80ceebef-f9aa-462e-a793-d3c1cf96123b"
    source_type = "image"
    destination_type = "volume"
    volume_size = 10
    boot_index = 0
    delete_on_termination = true
  }
}

resource "openstack_networking_floatingip_v2" "myvm_fip" {
  pool = "provider-199-2"
}

resource "openstack_compute_floatingip_associate_v2" "myvm_fip" {
  floating_ip = openstack_networking_floatingip_v2.myvm_fip.address
  instance_id = openstack_compute_instance_v2.myvm.id
}
```
This configuration defines an OpenStack provider, creates a compute instance named `myvm` with a specified flavour, key pair, and security groups. It connects to a network named `my-tenant-net` and boots from a 10GB volume based on a specific image UUID, which is deleted upon termination. It also allocates a floating IP from the `provider-199-2` pool and associates it with the `myvm` instance.
